logger = logging.getLogger()
logger.setLevel(os.getenv("LOG_LEVEL", "INFO"))

s3 = boto3.client("s3")
sns = boto3.client("sns")


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    output_bucket = os.getenv("OUTPUT_BUCKET")
    output_prefix = os.getenv("OUTPUT_PREFIX", "processed/")
    sns_topic_arn = os.getenv("SNS_TOPIC_ARN")

    if not output_bucket:
        raise ValueError("Missing required environment variable: OUTPUT_BUCKET")

    results = []

    for record in event.get("Records", []):
        try:
            if record.get("eventSource") != "aws:s3":
                logger.warning("Skipping non-S3 event record: %s", record)
                continue

            source_bucket = record["s3"]["bucket"]["name"]
            source_key = unquote_plus(record["s3"]["object"]["key"])

            logger.info("Processing object s3://%s/%s", source_bucket, source_key)

            obj = s3.get_object(Bucket=source_bucket, Key=source_key)
            body = obj["Body"].read()

            processed_body = process_image(body, source_key)

            output_key = build_output_key(output_prefix, source_key)
            s3.put_object(
                Bucket=output_bucket,
                Key=output_key,
                Body=processed_body,
                ContentType=obj.get("ContentType", "application/octet-stream"),
                Metadata={
                    "source-bucket": source_bucket,
                    "source-key": source_key,
                    "processed-by": "lambda-image-processor",
                },
            )

            message = {
                "status": "success",
                "source_bucket": source_bucket,
                "source_key": source_key,
                "output_bucket": output_bucket,
                "output_key": output_key,
                "request_id": getattr(context, "aws_request_id", None),
            }

            if sns_topic_arn:
                publish_sns(sns_topic_arn, message, subject="Image Processing Complete")

            logger.info("Successfully processed s3://%s/%s to s3://%s/%s", source_bucket, source_key, output_bucket, output_key)
            results.append(message)

        except Exception as e:
            error_message = {
                "status": "error",
                "error": str(e),
                "traceback": traceback.format_exc(),
                "record": record,
                "request_id": getattr(context, "aws_request_id", None),
            }
            logger.error("Failed processing record: %s", json.dumps(error_message))

            if sns_topic_arn:
                try:
                    publish_sns(sns_topic_arn, error_message, subject="Image Processing Failed")
                except Exception as sns_error:
                    logger.error("Failed to publish SNS error notification: %s", str(sns_error))

            results.append(error_message)

    return {
        "statusCode": 200,
        "body": json.dumps(
            {
                "message": "Processing complete",
                "results": results,
            }
        ),
    }


def process_image(image_bytes, source_key):
    logger.info("Processing image bytes for key: %s", source_key)
    return image_bytes


def build_output_key(prefix, source_key):
    normalized_prefix = prefix if prefix.endswith("/") or prefix == "" else prefix + "/"
    filename = source_key.split("/")[-1]
    return f"{normalized_prefix}{filename}"


def publish_sns(topic_arn, message, subject=None):
    params = {
        "TopicArn": topic_arn,
        "Message": json.dumps(message),
    }
    if subject:
        params["Subject"] = subject[:100]

    try:
        response = sns.publish(**params)
        logger.info("SNS publish response: %s", json.dumps(response, default=str))
        return response
    except ClientError:
        logger.exception("SNS publish failed")
        raise